import React from 'react';
import { useSelector } from 'react-redux';
import _ from 'lodash';
import { NavLink } from 'react-router-dom';
import  style  from './Home.module.css';


const Shop = (props) => {

    const products = useSelector(state => state.products);

    const handleChange = (event) => {
        event.preventDefault();
        const value = event.target.value;
        props.updateProductFilter(_.filter(products, product => {
            let isContains = product.name.toLowerCase().includes(value.toLowerCase())
            return isContains === true ? product : ''
        }));
    }

    return <React.Fragment>
        <div className={style.home} className={style.homeBanner}>
            <div className={style.homeContent}>
                <div>
                    <span className={style.homeContent_title}>Welcome to Rabbit Fresh Market</span>
                </div>
                <div>
                    <span className={style.homeContent_subtitle}>Local Foods at Good Price</span>
                </div>
                <div >
                    <div className={style.homeInput_wrapper}  >
                        <input className={style.homeInput} onChange={handleChange} type="text" name="name" id='name' placeholder="Search products..." />
                        <NavLink className={style.homeLink} to='/search'>
                            <i className={style.fas} className={style.faSearch} />
                        </NavLink>
                    </div>
                </div>
            </div>
        </div>
    </React.Fragment>
}

export default Shop;
